// === Validate Evolution API Signature ===
const crypto = require('crypto');

const payload = $input.first().json;
const headers = $input.first().headers || {};

// Signature from header
const receivedSignature = headers['x-evolution-signature'] || '';

// Get secret from credentials or env
const secret = $env.EVOLUTION_WEBHOOK_SECRET || 'test-secret';

// Generate expected signature
const expectedSignature = crypto
  .createHmac('sha256', secret)
  .update(JSON.stringify(payload))
  .digest('hex');

// Compare signatures (constant-time comparison to prevent timing attacks)
if (receivedSignature && !crypto.timingSafeEqual(
  Buffer.from(receivedSignature),
  Buffer.from(expectedSignature)
)) {
  throw new Error('Invalid signature - possible spoofing attack');
}

// Identify platform
let platform = 'whatsapp';
let senderId = '';
let messageText = '';
let messageId = '';

if (payload.data && payload.data.key && payload.data.key.remoteJid) {
  // WhatsApp (Evolution API format)
  platform = 'whatsapp';
  senderId = payload.data.key.remoteJid;
  messageText = payload.data.message?.conversation 
    || payload.data.message?.extendedTextMessage?.text 
    || '';
  messageId = payload.data.key.id;
} else if (payload.entry && payload.entry[0]?.messaging) {
  // Instagram (Graph API format)
  platform = 'instagram';
  const messaging = payload.entry[0].messaging[0];
  senderId = messaging.sender?.id || '';
  messageText = messaging.message?.text || '';
  messageId = messaging.message?.mid || '';
}

if (!messageText || !senderId) {
  throw new Error('Invalid message format - missing required fields');
}

return {
  platform,
  senderId,
  messageText: messageText.trim(),
  messageId,
  rawPayload: payload
};

// === Deduplication: Check if this message was already processed ===
const sqlite3 = require('better-sqlite3');
const path = require('path');

const msgId = $input.first().json.messageId;
const dbPath = path.join(process.env.N8N_SQLITE_DATABASE 
  || '/home/node/.n8n/database.sqlite', '../customer.db');

// Try to find the message in our conversations table
// Using n8n's built-in SQLite
let db;
try {
  db = new sqlite3(dbPath);

  // Ensure table exists
  db.exec(`
    CREATE TABLE IF NOT EXISTS conversations (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      platform TEXT NOT NULL,
      sender_id TEXT NOT NULL,
      message_id TEXT UNIQUE,
      role TEXT DEFAULT 'user',
      content TEXT NOT NULL,
      intent TEXT DEFAULT NULL,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    );
    CREATE INDEX IF NOT EXISTS idx_msg_id ON conversations(message_id);
    CREATE INDEX IF NOT EXISTS idx_sender ON conversations(sender_id, platform);
  `);

  const existing = db.prepare(
    'SELECT id FROM conversations WHERE message_id = ? LIMIT 1'
  ).get(msgId);

  if (existing) {
    // Message already processed - stop workflow
    return {
      deduplicated: true,
      status: 'skipped'
    };
  }

  db.close();
} catch (e) {
  console.error('DB error (dedup):', e.message);
  // Continue anyway to avoid blocking messages
}

return {
  deduplicated: false,
  ...$input.first().json
};

// === Save incoming message to SQLite ===
const sqlite3 = require('better-sqlite3');
const path = require('path');

const data = $input.first().json;
const dbPath = path.join('/home/node/.n8n', 'customer.db');

try {
  const db = new sqlite3(dbPath);

  // Ensure customers table exists
  db.exec(`
    CREATE TABLE IF NOT EXISTS customers (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      platform TEXT NOT NULL,
      external_id TEXT NOT NULL,
      name TEXT DEFAULT NULL,
      language TEXT DEFAULT 'ar',
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      UNIQUE(platform, external_id)
    );
  `);

  // Upsert customer
  db.prepare(`
    INSERT INTO customers (platform, external_id) 
    VALUES (?, ?)
    ON CONFLICT(platform, external_id) DO NOTHING
  `).run(data.platform, data.senderId);

  // Save the message
  db.prepare(`
    INSERT INTO conversations (platform, sender_id, message_id, role, content)
    VALUES (?, ?, ?, 'user', ?)
  `).run(data.platform, data.senderId, data.messageId, data.messageText);

  db.close();
} catch (e) {
  console.error('DB error (save):', e.message);
}

return $input.first().json;

// === Parse AI JSON response ===
const output = $input.first().json;

// Extract the message content
const content = output.message?.content || output.choices?.[0]?.message?.content || '{}';

// Try to parse JSON from the response
try {
  // Handle possible markdown code blocks
  let jsonStr = content;
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    jsonStr = jsonMatch[0];
  }

  const aiResponse = JSON.parse(jsonStr);

  return {
    ...$input.first().json,
    aiIntent: aiResponse.intent || 'general',
    aiReply: aiResponse.reply || 'شكراً لتواصلك معنا. سنعود إليك قريباً.',
    aiOrderNumber: aiResponse.order_number || null,
    aiConfidence: aiResponse.confidence || 0.5,
    searchQuery: aiResponse.search_query || null,
    orderProduct: aiResponse.order_product || null,
    orderQuantity: aiResponse.order_quantity || 1,
    customerPhone: aiResponse.customer_phone || null
  };
} catch (e) {
  // If JSON parsing fails, use the raw text as reply
  return {
    ...$input.first().json,
    aiIntent: 'general',
    aiReply: content.replace(/\{[\s\S]*\}/, '').trim() || content,
    aiOrderNumber: null,
    aiConfidence: 0.5,
    searchQuery: null,
    orderProduct: null,
    orderQuantity: 1
  };
}

